import React, { useMemo, useState } from "react";
import { createClient } from "@supabase/supabase-js";

/**
 * Modern, production-ready Login screen (no shadcn required)
 * - Pure TailwindCSS, zero extra component libs
 * - Glassmorphism card, animated gradient background
 * - Password visibility toggle, loading/disabled states, inline errors
 * - Uses Supabase email login if identifier is an email; otherwise falls back to legacy table lookup
 */

const SUPABASE_URL = (typeof import.meta !== "undefined" ? import.meta.env.VITE_SUPABASE_URL : undefined) || process.env.REACT_APP_SUPABASE_URL;
const SUPABASE_KEY = (typeof import.meta !== "undefined" ? import.meta.env.VITE_SUPABASE_KEY : undefined) || process.env.REACT_APP_SUPABASE_KEY;

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

export default function Login({ onLoginSuccess }) {
    const [identifier, setIdentifier] = useState(""); // email OR username (kullanici_adi)
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [showPw, setShowPw] = useState(false);

    const isEmail = useMemo(() => /.+@.+\..+/.test(identifier), [identifier]);

    const handleSupabaseAuth = async () => {
        const { data, error } = await supabase.auth.signInWithPassword({
            email: identifier,
            password,
        });
        if (error) throw error;
        const sessionUser = data?.user || null;
        localStorage.setItem("kullanici", JSON.stringify(sessionUser));
        return sessionUser;
    };

    // Fallback: your legacy table lookup ("Login" table with kullanici_adi/sifre)
    const handleLegacyTableLogin = async () => {
        const { data, error } = await supabase
            .from("Login")
            .select("*")
            .eq("kullanici_adi", identifier)
            .eq("sifre", password)
            .maybeSingle();

        if (error || !data) {
            const err = new Error("Hatalı kullanıcı adı veya şifre");
            err.code = "INVALID_CREDENTIALS";
            throw err;
        }

        // Tüm kullanıcı kaydını sakla (mevcut davranış)
        localStorage.setItem("kullanici", JSON.stringify(data));

        // REEL bilgileri (esnek alanlar)
        const reelUser =
            data?.Reel_kullanici ??
            data?.reel_kullanici ??
            data?.reelUserName ??
            data?.reel_username ??
            "";
        const reelPass =
            data?.Reel_sifre ??
            data?.reel_sifre ??
            data?.reelPassword ??
            data?.reel_password ??
            "";

        if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
        if (reelPass) localStorage.setItem("Reel_sifre", reelPass);
        if (reelUser && reelPass) {
            localStorage.setItem("reelCreds", JSON.stringify({ userName: reelUser, password: reelPass }));
        }

        return data;
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            if (isEmail) {
                await handleSupabaseAuth();
            } else {
                await handleLegacyTableLogin();
            }
            onLoginSuccess?.();
        } catch (err) {
            console.error("Login error:", err);
            setError(err?.message || "Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    const signInWithGoogle = async () => {
        try {
            setLoading(true);
            const { error } = await supabase.auth.signInWithOAuth({ provider: "google" });
            if (error) throw error;
        } catch (err) {
            console.error(err);
            setError("Google ile giriş yapılamadı. Daha sonra tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="relative min-h-screen w-full overflow-hidden bg-gradient-to-br from-zinc-900 via-slate-900 to-neutral-900 text-white">
            {/* Animated gradient blobs */}
            <div className="pointer-events-none absolute -top-24 -left-24 h-72 w-72 rounded-full bg-fuchsia-500/20 blur-3xl animate-pulse" />
            <div className="pointer-events-none absolute -bottom-28 -right-24 h-96 w-96 rounded-full bg-cyan-500/20 blur-3xl animate-[pulse_8s_ease-in-out_infinite]" />

            <div className="relative mx-auto flex min-h-screen max-w-7xl items-center justify-center px-4">
                {/* Glass card */}
                <div className="mx-auto w-full max-w-md rounded-2xl border border-white/10 bg-white/5 p-6 shadow-2xl shadow-black/40 backdrop-blur-xl">
                    <div className="mb-6 text-center">
                        <div className="mx-auto mb-3 flex h-12 w-12 items-center justify-center rounded-2xl bg-white/10">
                            {/* shield icon */}
                            <svg className="h-6 w-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10Z"></path><path d="M12 8v4"></path><path d="M12 16h.01"></path></svg>
                        </div>
                        <h2 className="text-2xl font-semibold tracking-tight">Giriş Yap</h2>
                        <p className="mt-1 text-sm text-white/60">{(isEmail ? "E-posta" : "Kullanıcı adı") + " ve şifrenizle devam edin"}</p>
                    </div>

                    {error && (
                        <div className="mb-4 rounded-xl border border-red-500/30 bg-red-500/10 p-3 text-red-200">
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleLogin} className="space-y-5">
                        <div className="space-y-2">
                            <label htmlFor="identifier" className="text-sm font-medium">Kullanıcı Adı / E‑posta</label>
                            <div className="relative">
                                <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-white/40">
                                    {/* mail icon */}
                                    <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M4 4h16v16H4z" /><path d="m22 6-10 7L2 6" /></svg>
                                </span>
                                <input
                                    id="identifier"
                                    type="text"
                                    value={identifier}
                                    onChange={(e) => setIdentifier(e.target.value)}
                                    placeholder="ornek@site.com veya kullanici_adi"
                                    autoComplete="username"
                                    required
                                    className="w-full rounded-xl border border-white/10 bg-white/5 px-10 py-2.5 text-white placeholder:text-white/40 focus:border-white/20 focus:outline-none"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label htmlFor="password" className="text-sm font-medium">Şifre</label>
                            <div className="relative">
                                <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-white/40">
                                    {/* lock icon */}
                                    <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="11" width="18" height="11" rx="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" /></svg>
                                </span>
                                <input
                                    id="password"
                                    type={showPw ? "text" : "password"}
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    placeholder="••••••••"
                                    autoComplete="current-password"
                                    required
                                    className="w-full rounded-xl border border-white/10 bg-white/5 px-10 py-2.5 pr-12 text-white placeholder:text-white/40 focus:border-white/20 focus:outline-none"
                                />
                                <button
                                    type="button"
                                    aria-label={showPw ? "Şifreyi gizle" : "Şifreyi göster"}
                                    onClick={() => setShowPw((v) => !v)}
                                    className="absolute right-2 top-1/2 -translate-y-1/2 rounded-md p-2 text-white/70 hover:text-white"
                                >
                                    {showPw ? (
                                        // eye-off
                                        <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m3 3 18 18" /><path d="M10.58 10.58a2 2 0 0 0 2.84 2.84" /><path d="M16.68 16.68C15.24 17.54 13.66 18 12 18 7 18 2.73 14.5 1 12c.64-.9 1.43-1.74 2.33-2.5" /><path d="M22.94 11.94A10.94 10.94 0 0 0 18 6c-.76-.57-1.6-1.03-2.5-1.36" /></svg>
                                    ) : (
                                        // eye
                                        <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8Z" /><circle cx="12" cy="12" r="3" /></svg>
                                    )}
                                </button>
                            </div>
                        </div>

                        <div className="flex items-center justify-between text-sm">
                            <label className="flex items-center gap-2 text-white/70">
                                <input type="checkbox" className="h-4 w-4 rounded border-white/20 bg-transparent" />
                                Beni hatırla
                            </label>
                            <a className="text-white/70 underline-offset-4 hover:underline" href="#" onClick={(e) => e.preventDefault()}>
                                Şifremi unuttum
                            </a>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="inline-flex w-full items-center justify-center gap-2 rounded-xl bg-white px-4 py-2.5 font-medium text-black shadow transition hover:bg-zinc-100 disabled:cursor-not-allowed disabled:opacity-70"
                        >
                            {loading ? (
                                <>
                                    <span className="h-4 w-4 animate-spin rounded-full border-2 border-black/50 border-r-transparent" />
                                    Giriş yapılıyor…
                                </>
                            ) : (
                                <>
                                    {/* login icon */}
                                    <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4" /><path d="m10 17 5-5-5-5" /><path d="M15 12H3" /></svg>
                                    Giriş
                                </>
                            )}
                        </button>

                        <div className="my-1 h-px w-full bg-white/10" />

                        <button
                            type="button"
                            disabled={loading}
                            onClick={signInWithGoogle}
                            className="inline-flex w-full items-center justify-center gap-2 rounded-xl border border-white/20 bg-white/5 px-4 py-2.5 font-medium text-white transition hover:bg-white/10 disabled:cursor-not-allowed disabled:opacity-70"
                        >
                            Google ile devam et
                        </button>

                        <p className="text-center text-xs text-white/50">
                            Devam ederek <a href="#" className="underline underline-offset-4">Kullanım Koşulları</a> ve <a href="#" className="underline underline-offset-4">Gizlilik</a>'i kabul etmiş olursunuz.
                        </p>
                    </form>
                </div>
            </div>
        </div>
    );
}
